UPDATE coaching.exercise_scaling_profile sp SET
  load_guidance = v.guidance,
  gender_specific_notes = CASE WHEN 'youth_beginner' = 'adult_beginner' THEN v.gender_notes ELSE sp.gender_specific_notes END
FROM (VALUES
  ('single-leg-balance-hold-tripod-foot', 'Use fingertip wall support and 5–10 second holds.', 'No default sex-based adjustment. Scale by balance quality, joint control, symptoms, fall risk, and supervision needs rather than gender alone.'),
  ('single-leg-balance-reach-clock-control', 'Two directions only with fingertip support.', 'No default sex-based adjustment. Scale by balance quality, joint control, symptoms, fall risk, and supervision needs rather than gender alone.'),
  ('y-balance-reach-star-reach', 'Use reach clock with shorter reaches before Y-Balance.', 'No default sex-based adjustment. Scale by balance quality, joint control, symptoms, fall risk, and supervision needs rather than gender alone.'),
  ('single-leg-rdl-reach-bodyweight-control', 'Kickstand RDL reach or wall-supported hinge.', 'No default sex-based adjustment. Scale by balance quality, joint control, symptoms, fall risk, and supervision needs rather than gender alone.'),
  ('hip-airplane-supported', 'Supported single-leg hinge hold, no rotation.', 'No default sex-based adjustment. Scale by balance quality, joint control, symptoms, fall risk, and supervision needs rather than gender alone.'),
  ('step-down-to-hover', 'Very low step with hand support.', 'No default sex-based adjustment. Scale by balance quality, joint control, symptoms, fall risk, and supervision needs rather than gender alone.'),
  ('lateral-step-down', 'Low step with hand support.', 'No default sex-based adjustment. Scale by balance quality, joint control, symptoms, fall risk, and supervision needs rather than gender alone.'),
  ('single-leg-squat-to-box', 'Supported single-leg sit-to-box or two-leg squat to box.', 'No default sex-based adjustment. Scale by balance quality, joint control, symptoms, fall risk, and supervision needs rather than gender alone.'),
  ('perturbation-single-leg-balance', 'Static single-leg balance first; use visual cue only.', 'No default sex-based adjustment. Scale by balance quality, joint control, symptoms, fall risk, and supervision needs rather than gender alone.'),
  ('beam-line-balance-freeze', 'Floor line walk with two-foot freeze.', 'No default sex-based adjustment. Scale by balance quality, joint control, symptoms, fall risk, and supervision needs rather than gender alone.')
) AS v(slug, guidance, gender_notes)
JOIN coaching.exercise e ON e.slug = v.slug
WHERE sp.exercise_id = e.id AND sp.cohort_key = 'youth_beginner';

