INSERT INTO coaching.education_content (
  entity_type, entity_key, entity_id, title, short_summary,
  what_it_is, why_it_works, why_it_matters, why_it_goes_here,
  programming_guidance, common_misuse, scaling_guidance
)
SELECT
  'exercise', e.slug, e.id, e.name, e.card_summary,
  e.description,
  v.why_works,
  'Develops position ownership, alignment, and low-speed joint resilience for safer Output and Capacity.',
  v.why_here,
  v.best_placement,
  v.misuse,
  v.scale_guidance
FROM (VALUES
  ('single-leg-balance-hold-tripod-foot', 'Static single-leg balance teaches the athlete to organize the foot, ankle, knee, hip, and trunk over one support leg before adding reach, rotation, perturbation, or load.', 'Belongs in single_leg_static_balance (521) — the baseline single-leg control slot before dynamic reach and step-down work.', 'Use early in Resilience blocks, after foot tripod or lower-leg prep and before dynamic reach, hinge, step-down, hop-to-stick, or loaded single-leg work.', 'Single-leg control should look quiet, aligned, and intentional. When it becomes rushed, loaded strength work, fatigue conditioning, or uncontrolled wobbling, reclassify the intent or regress the drill.', 'Regress reach distance, depth, surface challenge, rotation, or perturbation before accepting foot collapse, knee valgus, pelvic drop, or flailing. Hypermobility athletes need active joint control and should avoid hanging into passive end range.'),
  ('single-leg-balance-reach-clock-control', 'Reach-clock drills add movement around a stable single-leg base, challenging the athlete to maintain foot tripod, knee tracking, pelvis position, and trunk control while the free leg moves.', 'Belongs in single_leg_reach_control (522) — first dynamic reach progression after static single-leg balance.', 'Use after static balance and before Y-Balance, step-downs, single-leg RDL reaches, or low-amplitude single-leg hop-to-stick work.', 'Single-leg control should look quiet, aligned, and intentional. When it becomes rushed, loaded strength work, fatigue conditioning, or uncontrolled wobbling, reclassify the intent or regress the drill.', 'Regress reach distance, depth, surface challenge, rotation, or perturbation before accepting foot collapse, knee valgus, pelvic drop, or flailing. Hypermobility athletes need active joint control and should avoid hanging into passive end range.'),
  ('y-balance-reach-star-reach', 'Y-Balance and Star Excursion style reaches challenge single-leg dynamic balance and reach symmetry through anterior, posteromedial, posterolateral, or multi-direction reach patterns.', 'Belongs in multi_direction_reach_control (523) — formal dynamic reach after clock-reach control.', 'Use after reach-clock control and before step-downs, single-leg squats, hop-to-stick progressions, or return-to-sport balance screens.', 'Single-leg control should look quiet, aligned, and intentional. When it becomes rushed, loaded strength work, fatigue conditioning, or uncontrolled wobbling, reclassify the intent or regress the drill.', 'Regress reach distance, depth, surface challenge, rotation, or perturbation before accepting foot collapse, knee valgus, pelvic drop, or flailing. Hypermobility athletes need active joint control and should avoid hanging into passive end range.'),
  ('single-leg-rdl-reach-bodyweight-control', 'The single-leg RDL reach combines a hinge with single-leg balance and pelvis control so the athlete can practice hip control and foot/ankle stability before adding load.', 'Belongs in single_leg_hinge_control (524) — single-leg hinge ownership before loaded single-leg RDLs.', 'Use after static balance or reach clock and before loaded single-leg RDLs, hip airplanes, step-downs, or single-leg hop-to-stick drills.', 'Single-leg control should look quiet, aligned, and intentional. When it becomes rushed, loaded strength work, fatigue conditioning, or uncontrolled wobbling, reclassify the intent or regress the drill.', 'Regress reach distance, depth, surface challenge, rotation, or perturbation before accepting foot collapse, knee valgus, pelvic drop, or flailing. Hypermobility athletes need active joint control and should avoid hanging into passive end range.'),
  ('hip-airplane-supported', 'The supported hip airplane trains stance-hip control while the pelvis rotates open and closed over a stable leg, with support allowing rotation quality to stay ahead of balance challenge.', 'Belongs in hip_rotation_balance_control (525) — hip and pelvis rotation control after single-leg hinge ownership.', 'Use after single-leg RDL reach and before harder single-leg squat, lateral step-down, cutting, or unsupported hip airplane progressions.', 'Single-leg control should look quiet, aligned, and intentional. When it becomes rushed, loaded strength work, fatigue conditioning, or uncontrolled wobbling, reclassify the intent or regress the drill.', 'Regress reach distance, depth, surface challenge, rotation, or perturbation before accepting foot collapse, knee valgus, pelvic drop, or flailing. Hypermobility athletes need active joint control and should avoid hanging into passive end range.'),
  ('step-down-to-hover', 'Step-down tasks reveal and train lower-extremity control deficits around the knee and hip by requiring slow eccentric lowering and clean alignment.', 'Belongs in eccentric_stepdown_control (526) — controlled sagittal-plane step-down before lateral and single-leg squat progressions.', 'Use after static/reach balance and before lateral step-downs, single-leg squats, single-leg hop-to-stick, or deceleration control.', 'Single-leg control should look quiet, aligned, and intentional. When it becomes rushed, loaded strength work, fatigue conditioning, or uncontrolled wobbling, reclassify the intent or regress the drill.', 'Regress reach distance, depth, surface challenge, rotation, or perturbation before accepting foot collapse, knee valgus, pelvic drop, or flailing. Hypermobility athletes need active joint control and should avoid hanging into passive end range.'),
  ('lateral-step-down', 'The lateral step-down challenges the stance hip to control pelvic position and the stance knee to track during side-lowering, making frontal-plane compensation easy to coach.', 'Belongs in frontal_plane_stepdown_control (527) — lateral knee, hip, and pelvis control before lateral plyos and change of direction.', 'Use after step-down to hover and before lateral hop-to-stick, lateral bounds, lateral shuffle-to-stick, 90-degree cuts, or COD plant control.', 'Single-leg control should look quiet, aligned, and intentional. When it becomes rushed, loaded strength work, fatigue conditioning, or uncontrolled wobbling, reclassify the intent or regress the drill.', 'Regress reach distance, depth, surface challenge, rotation, or perturbation before accepting foot collapse, knee valgus, pelvic drop, or flailing. Hypermobility athletes need active joint control and should avoid hanging into passive end range.'),
  ('single-leg-squat-to-box', 'The single-leg squat trains lower-extremity and trunk neuromuscular control; a box target makes depth clear and keeps the athlete from chasing range they cannot own.', 'Belongs in single_leg_squat_control (528) — high-demand single-leg squat ownership after step-down control.', 'Use after step-down control and before single-leg hop-to-stick, loaded step-ups, COD plant control, or deeper unsupported single-leg squat progressions.', 'Single-leg control should look quiet, aligned, and intentional. When it becomes rushed, loaded strength work, fatigue conditioning, or uncontrolled wobbling, reclassify the intent or regress the drill.', 'Regress reach distance, depth, surface challenge, rotation, or perturbation before accepting foot collapse, knee valgus, pelvic drop, or flailing. Hypermobility athletes need active joint control and should avoid hanging into passive end range.'),
  ('perturbation-single-leg-balance', 'Perturbation-based balance training exposes the athlete to controlled disturbances so they can practice recovering posture and stability without turning the task into chaos.', 'Belongs in perturbation_balance (529) — reactive single-leg balance after static control is owned.', 'Use after static balance and reach control, before reactive balance games, single-leg hop-to-stick, COD plant control, or ninja balance tasks.', 'Single-leg control should look quiet, aligned, and intentional. When it becomes rushed, loaded strength work, fatigue conditioning, or uncontrolled wobbling, reclassify the intent or regress the drill.', 'Regress reach distance, depth, surface challenge, rotation, or perturbation before accepting foot collapse, knee valgus, pelvic drop, or flailing. Hypermobility athletes need active joint control and should avoid hanging into passive end range.'),
  ('beam-line-balance-freeze', 'Beam and line work narrows the base of support and makes foot placement visible, forcing controlled steps, freeze quality, and safe balance recovery.', 'Belongs in narrow_base_balance_control (530) — narrow-base stance, freeze control, and foot placement after foundational single-leg balance.', 'Use after single-leg balance hold, line walk, foot tripod shifts, or stick-shape freeze games and before beam movement progressions, ninja obstacles, cartwheel line drills, or landing freeze games.', 'Single-leg control should look quiet, aligned, and intentional. When it becomes rushed, loaded strength work, fatigue conditioning, or uncontrolled wobbling, reclassify the intent or regress the drill.', 'Regress reach distance, depth, surface challenge, rotation, or perturbation before accepting foot collapse, knee valgus, pelvic drop, or flailing. Hypermobility athletes need active joint control and should avoid hanging into passive end range.')
) AS v(slug, why_works, why_here, best_placement, misuse, scale_guidance)
JOIN coaching.exercise e ON e.slug = v.slug
ON CONFLICT (entity_type, entity_key, entity_id) DO UPDATE SET
  title = EXCLUDED.title,
  short_summary = EXCLUDED.short_summary,
  what_it_is = EXCLUDED.what_it_is,
  why_it_works = EXCLUDED.why_it_works,
  why_it_goes_here = EXCLUDED.why_it_goes_here,
  programming_guidance = EXCLUDED.programming_guidance,
  common_misuse = EXCLUDED.common_misuse,
  scaling_guidance = EXCLUDED.scaling_guidance,
  updated_at = now();
